// Assemble a compact payload for Claude — trim fields to keep tokens low.
const openRaw = $('Get Open Tasks').all().map(i => i.json).filter(t => t && t.task_id);
const suggestedRaw = $('Get Suggested Tasks').all().map(i => i.json).filter(t => t && t.task_id);
const memoriesRaw = $('Get Recent Memories').all().map(i => i.json).filter(m => m && m.memory_id);

const slimTask = t => ({
  task: t.task_text,
  urgency: t.urgency,
  due: t.due_date || null,
  category: t.category || null,
  who: t.entity_name || null,
  age_days: Math.round((Date.now() - new Date(t.created_date)) / 86400000),
});

const payload = {
  date_nz: new Date().toLocaleDateString('en-NZ', { weekday: 'long', day: 'numeric', month: 'long', timeZone: 'Pacific/Auckland' }),
  open_tasks: openRaw.slice(0, 40).map(slimTask),
  suggested_inbox: suggestedRaw.slice(0, 10).map(slimTask),
  recent_memories: memoriesRaw.slice(0, 8).map(m => ({
    date: (m.created_at || '').slice(0, 10),
    theme: (m.main_theme || m.summary || '').split('\n')[0].slice(0, 180),
  })),
};

const system = `You are Zane's chief of staff writing his 6am daily brief. Zane runs Moore AI Studios (AI solutions for small businesses in NZ; current clients/projects: Jake at Core Finance, Greenmachine, plus his own content/marketing and the Command Centre system).\n\nYou get JSON: open_tasks (already sorted soonest-due, most urgent first), suggested_inbox (auto-extracted tasks he hasn't accepted yet), recent_memories (what happened lately).\n\nWrite a Telegram message using ONLY these HTML tags: <b>, <i>. No markdown, no headers, no other tags. Under 3200 characters. Structure:\n1. One short greeting line with the date. No fluff, no 'I hope'.\n2. <b>Top 3 today</b> — the three highest-leverage tasks. One line each: the task, then <i>why now</i> (deadline, client momentum, what it unblocks). Choose by judgement, not just list order.\n3. <b>Also on the board</b> — up to 4 more worth remembering, grouped by client/project, one line each.\n4. <b>Inbox to triage</b> — only if suggested_inbox is non-empty: up to 5, one line each, so he can keep/dismiss on the check-in page.\n5. <b>Watch</b> — only if recent_memories reveal an open loop, risk, or someone he's waiting on: one or two lines.\n\nBe specific — use client and task names from the data. Never invent tasks or deadlines. Total read time should be under a minute.`;

return [{
  json: {
    anthropic_body: {
      model: 'claude-sonnet-5',
      max_tokens: 1600,
      thinking: { type: 'disabled' },
      system,
      messages: [{ role: 'user', content: JSON.stringify(payload) }],
    },
  },
}];

// Replace REPLACE_WITH_CHECKIN_TOKEN with the real CHECKIN_TOKEN value.
const CHECKIN_URL = 'https://cais-mcp-server.onrender.com/checkin?token=REPLACE_WITH_CHECKIN_TOKEN';

const res = $json;
// Sonnet 5 runs adaptive thinking by default — take only the text blocks.
let text = (res.content || [])
  .filter(b => b.type === 'text')
  .map(b => b.text)
  .join('\n')
  .trim();

if (!text) {
  text = '<b>Daily brief failed to generate</b> — check the daily-brief workflow execution log.';
}

const footer = `\n\n<a href="${CHECKIN_URL}">Open today's check-in →</a>`;
const MAX = 4096 - footer.length - 20;
if (text.length > MAX) {
  text = text.slice(0, MAX) + '…';
}

return [{ json: { message: text + footer } }];
